<div class="page-title-row"><div><span class="text-muted">Administration</span><h1>Microsoft 365</h1><p class="text-muted mb-0">One place for Graph, calendar, SharePoint, Teams, and webhook health.</p></div><a class="btn btn-outline-primary" href="/portal/graph-diagnostics"><i class="fa-brands fa-microsoft me-2"></i>Graph diagnostics</a></div>
<div class="row g-4 mb-4"><?php foreach(['graph','sharepoint','teams'] as $key):$item=$health[$key];$state=!$item['configured']?'secondary':($item['healthy']===false?'danger':($item['healthy']===true?'success':'warning'));?><div class="col-lg-4"><div class="portal-card p-4 h-100"><div class="d-flex justify-content-between"><h2 class="h5"><?=e($item['name'])?></h2><span class="badge text-bg-<?=$state?>"><?=$item['healthy']===true?'Connected':($item['healthy']===false?'Failed':($item['configured']?'Needs test':'Missing'))?></span></div><p class="text-muted small"><?=e($item['detail'])?></p><?php if($item['last_tested_at']??null):?><div class="small text-muted">Last tested <?=e($item['last_tested_at'])?></div><?php endif?><?php if($key==='teams'):?><form method="post" action="/portal/integrations/teams/test" class="mt-3"><?=csrf_field()?><button class="btn btn-sm btn-primary"><i class="fa-brands fa-microsoft-teams me-2"></i>Send Teams test</button></form><?php endif?></div></div><?php endforeach?></div>
<div class="row g-4"><div class="col-xl-6"><div class="portal-card p-4"><h2 class="h5">Loaded configuration</h2><div class="table-responsive"><table class="table align-middle mb-0"><tbody><?php foreach($config as $label=>$value):?><tr><th><?=e($label)?></th><td class="font-monospace small"><?=e($value)?></td></tr><?php endforeach?></tbody></table></div></div></div><div class="col-xl-6"><div class="portal-card p-4"><h2 class="h5">Graph subscriptions</h2><?php if(!$subscriptions):?><p class="text-muted mb-0">No stored Graph subscriptions.</p><?php else:?><div class="table-responsive"><table class="table"><thead><tr><th>Resource</th><th>Change</th><th>Expires</th></tr></thead><tbody><?php foreach($subscriptions as $s):?><tr><td class="small"><?=e($s['resource'])?></td><td><?=e($s['change_type'])?></td><td><?=e($s['expiration_at'])?></td></tr><?php endforeach?></tbody></table></div><?php endif?></div></div></div>
